        "peculiar breed":                       { section:"reading", ipa:"/pɪˈkjuː.li.ər/", stressed:"Kiu", meaning:"một giống người đặc biệt / khác thường", type:"phrase", collocation:"a peculiar breed of people", example:"Explorers have always been a peculiar breed, driven by curiosity rather than comfort.", connotation:"neutral" },
        "enquiring instinct":                   { section:"reading", ipa:"/ɪnˈkwaɪə.rɪŋ/", stressed:"Kwai", meaning:"bản năng tìm tòi", type:"phrase", collocation:"driven by an enquiring instinct", example:"Great scientists share an enquiring instinct that compels them to question established knowledge.", connotation:"positive" },
        "borders of the unknown are being tested": { section:"reading", ipa:"/ˈbɔː.dəz/", stressed:"Bor", meaning:"ranh giới của điều chưa biết đang bị thử thách", type:"phrase", collocation:"push the borders of the unknown", example:"In every generation, the borders of the unknown are being tested by those who refuse to accept limits.", connotation:"positive" },
